const baseStores = [
  { site: "Amazon", rating: 4.6, link: "https://amazon.in" },
  { site: "Flipkart", rating: 4.5, link: "https://flipkart.com" },
  { site: "Croma", rating: 4.4, link: "https://croma.com" },
  { site: "Reliance Digital", rating: 4.3, link: "https://reliancedigital.in" },
  { site: "Tata CLiQ", rating: 4.2, link: "https://tatacliq.com" },
  { site: "Vijay Sales", rating: 4.4, link: "https://vijaysales.com" },
  { site: "Snapdeal", rating: 4.1, link: "https://snapdeal.com" }
];

const generateStores = (basePrice) => {
  return baseStores.map((s, i) => ({
    ...s,
    price: basePrice + (i * 500 - 1500)
  }));
};

const products = [

  { name:"iPhone 15", image:"https://images.unsplash.com/photo-1511707171634-5f897ff02aa9", rating:4.7, reviews:2345, stores:generateStores(75000) },
  { name:"Samsung S23", image:"https://images.unsplash.com/photo-1510557880182-3d4d3cba35a5", rating:4.5, reviews:1820, stores:generateStores(70000) },

  { name:"MacBook Air M2", image:"https://images.unsplash.com/photo-1517336714731-489689fd1ca8", rating:4.8, reviews:1290, stores:generateStores(110000) },
  { name:"Dell XPS 13", image:"https://images.unsplash.com/photo-1496181133206-80ce9b88a853", rating:4.6, reviews:870, stores:generateStores(100000) },
  { name:"HP Pavilion Laptop", image:"https://images.unsplash.com/photo-1517336714731-489689fd1ca8", rating:4.4, reviews:980, stores:generateStores(60000) },

  { name:"Sony Headphones", image:"https://images.unsplash.com/photo-1505740420928-5e560c06d30e", rating:4.6, reviews:980, stores:generateStores(9000) },
  { name:"Boat Headphones", image:"https://images.unsplash.com/photo-1505740420928-5e560c06d30e", rating:4.3, reviews:1700, stores:generateStores(2500) },

  { name:"Apple Watch", image:"https://images.unsplash.com/photo-1516574187841-cb9cc2ca948b", rating:4.7, reviews:1540, stores:generateStores(38000) },
  { name:"Noise Smartwatch", image:"https://images.unsplash.com/photo-1516574187841-cb9cc2ca948b", rating:4.2, reviews:1500, stores:generateStores(5000) },

  { name:"iPad Air", image:"https://images.unsplash.com/photo-1587825140708-dfaf72ae4b04", rating:4.7, reviews:1120, stores:generateStores(56000) },
  { name:"Samsung Tablet", image:"https://images.unsplash.com/photo-1587825140708-dfaf72ae4b04", rating:4.5, reviews:890, stores:generateStores(30000) },

  { name:"Canon DSLR", image:"https://images.unsplash.com/photo-1516035069371-29a1b244cc32", rating:4.5, reviews:760, stores:generateStores(45000) },

  { name:"Logitech Mouse", image:"https://images.unsplash.com/photo-1587829741301-dc798b83add3", rating:4.4, reviews:2210, stores:generateStores(1500) },

  { name:"Gaming Keyboard", image:"https://images.unsplash.com/photo-1618384887929-16ec33fab9ef", rating:4.5, reviews:1340, stores:generateStores(4000) },

  { name:"OnePlus 11", image:"https://images.unsplash.com/photo-1598327105666-5b89351aff97", rating:4.6, reviews:2100, stores:generateStores(65000) }

];

export default products;
